/* ROT_SHIFT_IXD_R - rotate */
static void inst_ROT_SHIFT_IXD_R(CPUState *cpu, DecodedInstruction *inst) {
    uint16_t addr = (uint16_t)(cpu->ix + (int8_t)inst->disp);
    uint8_t op = inst->op & 0x07;
    uint8_t r = inst->r & 0x07;
    uint8_t value = z80_read_byte(cpu, addr);
    uint8_t carry_in = cpu->flags.C ? 1u : 0u;
    uint8_t carry_out = 0u;
    switch (op) {
    case 0:  /* RLC */
    carry_out = (value & 0x80) ? 1u : 0u;
    value = (uint8_t)((value << 1) | carry_out);
    break;
    case 1:  /* RRC */
    carry_out = value & 0x01;
    value = (uint8_t)((value >> 1) | (carry_out << 7));
    break;
    case 2:  /* RL */
    carry_out = (value & 0x80) ? 1u : 0u;
    value = (uint8_t)((value << 1) | carry_in);
    break;
    case 3:  /* RR */
    carry_out = value & 0x01;
    value = (uint8_t)((value >> 1) | (carry_in << 7));
    break;
    case 4:  /* SLA */
    carry_out = (value & 0x80) ? 1u : 0u;
    value = (uint8_t)(value << 1);
    break;
    case 5:  /* SRA */
    carry_out = value & 0x01;
    value = (uint8_t)((value >> 1) | (value & 0x80));
    break;
    case 6:  /* SLL */
    carry_out = (value & 0x80) ? 1u : 0u;
    value = (uint8_t)((value << 1) | 0x01u);
    break;
    default: /* SRL */
    carry_out = value & 0x01;
    value = (uint8_t)(value >> 1);
    break;
    }
    z80_write_byte(cpu, addr, value);
    if (r != 6) {
    if (r == 0) cpu->registers[REG_B] = value;
    else if (r == 1) cpu->registers[REG_C] = value;
    else if (r == 2) cpu->registers[REG_D] = value;
    else if (r == 3) cpu->registers[REG_E] = value;
    else if (r == 4) cpu->registers[REG_H] = value;
    else if (r == 5) cpu->registers[REG_L] = value;
    else cpu->registers[REG_A] = value;
    }
    cpu->flags.C = (carry_out != 0);
    cpu->flags.Z = (value == 0);
    cpu->flags.S = ((value & 0x80) != 0);
    cpu->flags.H = (false);
    cpu->flags.P = (cpu_parity(value));
    cpu->flags.N = (false);
    cpu->total_cycles += 23;
}

